'use client';

import React from 'react';

interface KPICardProps {
  title: string;
  value: string | number;
  subtitle?: string;
  borderColor?: string;
  icon?: React.ReactNode;
  loading?: boolean;
  tooltip?: string;
  onClick?: () => void;
}

/**
 * KPI Card Component
 *
 * Displays a single KPI metric with title, value, and optional subtitle.
 * Uses EN 15380 railway terminology.
 */
export function KPICard({
  title,
  value,
  subtitle,
  borderColor = 'border-primary-500',
  icon,
  loading = false,
  tooltip,
  onClick,
}: KPICardProps) {
  return (
    <div
      className={`bg-white shadow rounded-lg p-4 border-l-4 ${borderColor} transition-all duration-200 hover:shadow-md ${onClick ? 'cursor-pointer' : ''}`}
      title={tooltip}
      onClick={onClick}
      role={onClick ? 'button' : undefined}
      tabIndex={onClick ? 0 : undefined}
    >
      <div className="flex items-center justify-between">
        <div className="text-sm font-medium text-gray-500">{title}</div>
        {icon && <div className="flex-shrink-0">{icon}</div>}
      </div>
      <div className="mt-2">
        {loading ? (
          <div className="animate-pulse">
            <div className="h-8 bg-gray-200 rounded w-20"></div>
          </div>
        ) : (
          <div className="text-3xl font-bold text-gray-900">{value}</div>
        )}
      </div>
      {subtitle && !loading && (
        <div className="mt-1 text-sm text-gray-500">{subtitle}</div>
      )}
    </div>
  );
}

'use client';

import React from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';

const navItems = [
  { href: '/', label: 'Dashboard' },
  { href: '/map', label: 'Map' },
  { href: '/allocation', label: 'Allocation' },
  { href: '/fleet', label: 'Fleet' },
  { href: '/balancing', label: 'Balancing' },
  { href: '/maintenance', label: 'Maintenance' },
];

/**
 * Main Navigation Component
 *
 * Provides navigation links to all main pages.
 * Highlights the current active page.
 */
export function Navigation() {
  const pathname = usePathname();

  return (
    <nav className="bg-white shadow-sm border-b border-gray-200">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16">
          <div className="flex items-center">
            <Link href="/" className="flex items-center">
              <span className="text-xl font-bold text-primary-600">MMS</span>
              <span className="ml-2 text-sm text-gray-500 hidden sm:block">
                Metro Mileage Management
              </span>
            </Link>

            {/* Nav Links */}
            <div className="hidden md:flex ml-10 space-x-4">
              {navItems.map((item) => {
                const isActive = pathname === item.href ||
                  (item.href !== '/' && pathname.startsWith(item.href));

                return (
                  <Link
                    key={item.href}
                    href={item.href}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                      isActive
                        ? 'bg-primary-100 text-primary-700'
                        : 'text-gray-600 hover:bg-gray-100 hover:text-gray-900'
                    }`}
                  >
                    {item.label}
                  </Link>
                );
              })}
            </div>
          </div>

          {/* Demo Badge */}
          <div className="flex items-center">
            <span className="px-2 py-1 text-xs font-medium bg-amber-100 text-amber-800 rounded">
              DEMO
            </span>
          </div>
        </div>
      </div>
    </nav>
  );
}

