'use client';

import React, { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { KPICard } from './KPICard';
import { dashboardApi, DashboardSummary } from '@/lib/api';

// Status icons as SVG components
const CheckIcon = () => (
  <svg className="w-6 h-6 text-variance-green" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
  </svg>
);

const WarningIcon = () => (
  <svg className="w-6 h-6 text-variance-yellow" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
  </svg>
);

const AlertIcon = () => (
  <svg className="w-6 h-6 text-variance-red" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
  </svg>
);

const TrainIcon = () => (
  <svg className="w-6 h-6 text-primary-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
  </svg>
);

const AvailableIcon = () => (
  <svg className="w-6 h-6 text-status-available" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
  </svg>
);

const MaintenanceIcon = () => (
  <svg className="w-6 h-6 text-status-maintenance" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
  </svg>
);

/**
 * Dashboard KPIs Component
 *
 * Displays the four main fleet KPIs:
 * - Total Trains
 * - Available Trains
 * - In Maintenance
 * - Km Variance (with traffic-light indicator)
 */
export function DashboardKPIs() {
  const router = useRouter();
  const [summary, setSummary] = useState<DashboardSummary | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function fetchSummary() {
      setLoading(true);
      const { data, error } = await dashboardApi.getSummary();

      if (error) {
        setError(error);
      } else if (data) {
        setSummary(data);
      }
      setLoading(false);
    }

    fetchSummary();
  }, []);

  // Determine variance border color and icon based on status
  const getVarianceConfig = (status?: 'green' | 'yellow' | 'red') => {
    switch (status) {
      case 'green':
        return {
          borderColor: 'border-variance-green',
          icon: <CheckIcon />,
          subtitle: 'Target met',
        };
      case 'yellow':
        return {
          borderColor: 'border-variance-yellow',
          icon: <WarningIcon />,
          subtitle: 'Attention needed',
        };
      case 'red':
        return {
          borderColor: 'border-variance-red',
          icon: <AlertIcon />,
          subtitle: 'Critical variance',
        };
      default:
        return {
          borderColor: 'border-gray-300',
          icon: null,
          subtitle: undefined,
        };
    }
  };

  // Calculate available percentage
  const availablePercentage = summary
    ? Math.round((summary.availableTrains / summary.totalTrains) * 100)
    : 0;

  const varianceConfig = getVarianceConfig(summary?.varianceStatus);

  if (error) {
    return (
      <div className="bg-red-50 border border-red-200 rounded-lg p-4">
        <p className="text-red-800">
          <strong>Error loading dashboard:</strong> {error}
        </p>
        <p className="mt-2 text-red-600 text-sm">
          Make sure the API server is running at{' '}
          <code className="bg-red-100 px-1 rounded">http://localhost:4000</code>
        </p>
      </div>
    );
  }

  // Navigation handlers
  const handleNavigateFleet = () => router.push('/fleet');
  const handleNavigateAvailable = () => router.push('/fleet?status=fit');
  const handleNavigateMaintenance = () => router.push('/maintenance');
  const handleNavigateBalancing = () => router.push('/balancing');

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
      <KPICard
        title="Total Trains"
        value={summary?.totalTrains ?? '--'}
        borderColor="border-primary-500"
        icon={<TrainIcon />}
        loading={loading}
        onClick={handleNavigateFleet}
        tooltip="Click to view all trains"
      />
      <KPICard
        title="Available"
        value={summary ? `${summary.availableTrains}` : '--'}
        subtitle={summary ? `${availablePercentage}% of fleet` : undefined}
        borderColor="border-status-available"
        icon={<AvailableIcon />}
        loading={loading}
